arguments.file_text:
@page "/apply/personal-info"
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply — Personal Info</PageTitle>

<h1>Step 1: Personal Information</h1>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="AppState.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email Address</label>
    <input class="form-control" type="email" @bind="AppState.Email" />
</div>

<button class="btn btn-primary" @onclick="Next">Next →</button>

@code {
    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress
        {
            CurrentStep = 1,
            CompletedSteps = ProgressSource is not null
                ? (await GetCurrentProgress()).CompletedSteps
                : new bool[4]
        });
    }

    private async Task<WizardProgress> GetCurrentProgress()
    {
        // Re-read from the source isn't directly possible, so we build from app state
        var p = new WizardProgress { CurrentStep = 1 };
        if (!string.IsNullOrWhiteSpace(AppState.Name)) p.CompletedSteps[0] = true;
        if (AppState.JobHistory.Count > 0) p.CompletedSteps[1] = true;
        if (AppState.References.Count > 0) p.CompletedSteps[2] = true;
        return p;
    }

    private async Task Next()
    {
        AppState.NotifyStateChanged();
        var progress = await GetCurrentProgress();
        progress.CompletedSteps[0] = true;
        progress.CurrentStep = 2;
        await ProgressSource.NotifyChangedAsync(progress);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply — Experience</PageTitle>

<h1>Step 2: Work Experience</h1>

@foreach (var (job, i) in AppState.JobHistory.Select((j, i) => (j, i)))
{
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between">
            <strong>@job.Company — @job.Title (@job.Years)</strong>
            <button class="btn btn-sm btn-outline-danger" @onclick="() => Remove(i)">Remove</button>
        </div>
    </div>
}

<h5>Add a position</h5>
<div class="row g-2 mb-3">
    <div class="col-md-4">
        <input class="form-control" placeholder="Company" @bind="newCompany" />
    </div>
    <div class="col-md-4">
        <input class="form-control" placeholder="Job Title" @bind="newTitle" />
    </div>
    <div class="col-md-2">
        <input class="form-control" placeholder="Years" @bind="newYears" />
    </div>
    <div class="col-md-2">
        <button class="btn btn-outline-primary w-100" @onclick="Add">Add</button>
    </div>
</div>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private string newCompany = string.Empty;
    private string newTitle = string.Empty;
    private string newYears = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        await UpdateProgress(2);
    }

    private void Add()
    {
        if (!string.IsNullOrWhiteSpace(newCompany))
        {
            AppState.JobHistory.Add(new JobEntry
            {
                Company = newCompany,
                Title = newTitle,
                Years = newYears
            });
            newCompany = newTitle = newYears = string.Empty;
        }
    }

    private void Remove(int index) => AppState.JobHistory.RemoveAt(index);

    private async Task UpdateProgress(int step)
    {
        var p = BuildProgress(step);
        await ProgressSource.NotifyChangedAsync(p);
    }

    private WizardProgress BuildProgress(int step)
    {
        var p = new WizardProgress { CurrentStep = step };
        if (!string.IsNullOrWhiteSpace(AppState.Name)) p.CompletedSteps[0] = true;
        if (AppState.JobHistory.Count > 0) p.CompletedSteps[1] = true;
        if (AppState.References.Count > 0) p.CompletedSteps[2] = true;
        return p;
    }

    private async Task Back()
    {
        AppState.NotifyStateChanged();
        await UpdateProgress(1);
        Nav.NavigateTo("/apply/personal-info");
    }

    private async Task Next()
    {
        AppState.NotifyStateChanged();
        var p = BuildProgress(3);
        p.CompletedSteps[1] = true;
        await ProgressSource.NotifyChangedAsync(p);
