@code {
    private string newCompany = string.Empty;
    private string newTitle = string.Empty;
    private string newYears = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        await UpdateProgress(2);
    }

    private void Add()
    {
        if (!string.IsNullOrWhiteSpace(newCompany))
        {
            AppState.JobHistory.Add(new JobEntry
            {
                Company = newCompany,
                Title = newTitle,
                Years = newYears
            });
            newCompany = newTitle = newYears = string.Empty;
        }
    }

    private void Remove(int index) => AppState.JobHistory.RemoveAt(index);

    private async Task UpdateProgress(int step)
    {
        var p = BuildProgress(step);
        await ProgressSource.NotifyChangedAsync(p);
    }

    private WizardProgress BuildProgress(int step)
    {
        var p = new WizardProgress { CurrentStep = step };
        if (!string.IsNullOrWhiteSpace(AppState.Name)) p.CompletedSteps[0] = true;
        if (AppState.JobHistory.Count > 0) p.CompletedSteps[1] = true;
        if (AppState.References.Count > 0) p.CompletedSteps[2] = true;
        return p;
    }

    private async Task Back()
    {
        AppState.NotifyStateChanged();
        await UpdateProgress(1);
        Nav.NavigateTo("/apply/personal-info");
    }

    private async Task Next()
    {
        AppState.NotifyStateChanged();
        var p = BuildProgress(3);
        p.CompletedSteps[1] = true;
        await ProgressSource.NotifyChangedAsync(p);
        Nav.NavigateTo("/apply/references");
    }
}

