toolArgs.file_text:
@page "/apply/review"
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply — Review</PageTitle>

<h1>Step 4: Review Your Application</h1>

<div class="card mb-4 p-3">
    <h5>Personal Information</h5>
    <p><strong>Name:</strong> @AppState.Name</p>
    <p><strong>Email:</strong> @AppState.Email</p>
</div>

<div class="card mb-4 p-3">
    <h5>Work Experience</h5>
    @if (AppState.JobHistory.Count == 0)
    {
        <p class="text-muted">No positions added.</p>
    }
    else
    {
        <ul>
            @foreach (var job in AppState.JobHistory)
            {
                <li>@job.Company — @job.Title (@job.Years)</li>
            }
        </ul>
    }
</div>

<div class="card mb-4 p-3">
    <h5>References</h5>
    @if (AppState.References.Count == 0)
    {
        <p class="text-muted">No references added.</p>
    }
    else
    {
        <ul>
            @foreach (var r in AppState.References)
            {
                <li>@r.Name — @r.Relationship (@r.Phone)</li>
            }
        </ul>
    }
</div>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (submitted)
{
    <div class="alert alert-success mt-3">Application submitted successfully!</div>
}

@code {
    private bool submitted;

    protected override async Task OnInitializedAsync()
    {
        var p = BuildProgress(4);
        await ProgressSource.NotifyChangedAsync(p);
    }

    private WizardProgress BuildProgress(int step)
    {
        var p = new WizardProgress { CurrentStep = step };
        if (!string.IsNullOrWhiteSpace(AppState.Name)) p.CompletedSteps[0] = true;
        if (AppState.JobHistory.Count > 0) p.CompletedSteps[1] = true;
        if (AppState.References.Count > 0) p.CompletedSteps[2] = true;
        return p;
    }

    private async Task Back()
    {
        await ProgressSource.NotifyChangedAsync(BuildProgress(3));
        Nav.NavigateTo("/apply/references");
    }

    private async Task Submit()
    {
        var p = BuildProgress(4);
        p.CompletedSteps[3] = true;
        await ProgressSource.NotifyChangedAsync(p);
        submitted = true;
    }
}

